public:
int binarySearch(vector<int>& arr, int target, bool find_first_occurrence) {
    int low = 0, high = arr.size() - 1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (arr[mid] == target) {
            if (find_first_occurrence) {
                while (mid > 0 && arr[mid - 1] == target) {
                    mid--;
                }
                return mid;
            } else {
                while (mid < arr.size() - 1 && arr[mid + 1] == target) {
                    mid++;
                }
                return mid;
            }
        } else if (arr[mid] < target) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    return -1;
}
};

