import sys

class Solution:
    def binarySearch(self, arr, target, find_first_occurrence):
        low = 0
        high = len(arr) - 1
        while low <= high:
            mid = low + (high - low) // 2
            if arr[mid] == target:
                if find_first_occurrence:
                    while mid > 0 and arr[mid - 1] == target:
                        mid -= 1
                    return mid
                else:
                    while mid < len(arr) - 1 and arr[mid + 1] == target:
                        mid += 1
                    return mid
            elif arr[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return -1

if __name__ == '__main__':
    n = int(input())
    arr = list(map(int, input().split()))
    target = int(input())
    find_first_occurrence = input() == 'True'
    solution = Solution()
    result = solution.binarySearch(arr, target, find_first_occurrence)
    print(result)

